#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int val;
    struct Node *next;
} Node;

Node* build(int n) {
    Node *head = NULL, *tail = NULL;
    for (int i = 0; i < n; ++i) {
        int x; scanf("%d", &x);
        Node *tmp = (Node*)malloc(sizeof(Node));
        tmp->val = x; tmp->next = NULL;
        if (!head) head = tail = tmp; else { tail->next = tmp; tail = tmp; }
    }
    return head;
}

Node* removeDuplicates(Node* head) {
    Node *cur = head;
    while (cur && cur->next) {
        if (cur->val == cur->next->val) {
            Node *dup = cur->next;
            cur->next = dup->next;
            free(dup);
        } else {
            cur = cur->next;
        }
    }
    return head;
}

void printList(Node* head) {
    for (Node* p = head; p; p = p->next) {
        printf("%d", p->val);
        if (p->next) printf(" ");
    }
    printf("\n");
}

void freeList(Node* head) {
    while (head) { Node* tmp = head; head = head->next; free(tmp); }
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node* head = build(N);
        head = removeDuplicates(head);
        printList(head);
        freeList(head);
    }
    return 0;
}

