import java.io.*;
import java.util.*;

class Main {
    static class Node {
        long val;
        Node next;
        Node(long v) { val = v; }
    }

    private static Node build(int n, FastScanner fs) throws IOException {
        Node head = null, tail = null;
        for (int i = 0; i < n; i++) {
            long x = fs.nextLong();
            Node tmp = new Node(x);
            if (head == null) head = tail = tmp; else { tail.next = tmp; tail = tmp; }
        }
        return head;
    }

    private static Node removeDuplicates(Node head) {
        Node cur = head;
        while (cur != null && cur.next != null) {
            if (cur.val == cur.next.val) {
                cur.next = cur.next.next;
            } else {
                cur = cur.next;
            }
        }
        return head;
    }

    private static void print(Node head, StringBuilder sb) {
        for (Node p = head; p != null; p = p.next) {
            sb.append(p.val);
            if (p.next != null) sb.append(' ');
        }
        sb.append('\n');
    }

    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        while (T-- > 0) {
            int N = fs.nextInt();
            Node head = build(N, fs);
            head = removeDuplicates(head);
            print(head, out);
        }
        System.out.print(out.toString());
    }

    // Fast scanner for speed
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { return Long.parseLong(next()); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
    }
}

