#!/usr/bin/env python3
import sys

def removeDuplicates(head):
    cur = head
    while cur and cur.next:
        if cur.val == cur.next.val:
            cur.next = cur.next.next
        else:
            cur = cur.next
    return head

class ListNode:
    __slots__ = ('val', 'next')
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def build(arr):
    if not arr:
        return None
    head = ListNode(arr[0])
    cur = head
    for v in arr[1:]:
        cur.next = ListNode(v)
        cur = cur.next
    return head

def to_list(head):
    res = []
    while head:
        res.append(str(head.val))
        head = head.next
    return ' '.join(res)

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        n = int(data[idx]); idx += 1
        arr = list(map(int, data[idx:idx+n])); idx += n
        head = build(arr)
        head = removeDuplicates(head)
        out_lines.append(to_list(head))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

